class PaymentProcessingError(Exception):
    pass


class AuthorizationError(Exception):
    pass


VALID_ROLES = {"basic", "premium", "enterprise"}

DISCOUNT_MAP = {
    "basic": 0.0,
    "premium": 0.15,
    "enterprise": 0.30,
}


def get_verified_user_role(user, user_repository=None):
    """
    Fetch the user's role from a trusted server-side source rather than
    trusting the client-supplied role field.
    """
    if user_repository is not None:
        verified_user = user_repository.get_user_by_id(user.get("id"))
        if verified_user is None:
            raise AuthorizationError(f"User with id {user.get('id')} not found.")
        role = verified_user.get("role", "").lower().strip()
    else:
        role = user.get("role", "").lower().strip()

    if role not in VALID_ROLES:
        raise AuthorizationError(f"Invalid user role: '{role}'. Must be one of {VALID_ROLES}.")

    return role


def validate_user(user):
    if not isinstance(user, dict):
        raise PaymentProcessingError("User must be a dictionary.")
    if "id" not in user:
        raise PaymentProcessingError("User must have an 'id' field.")
    if "role" not in user:
        raise PaymentProcessingError("User must have a 'role' field.")


def validate_cart_items(cart_items):
    if not isinstance(cart_items, list):
        raise PaymentProcessingError("Cart items must be a list.")
    if len(cart_items) == 0:
        raise PaymentProcessingError("Cart must contain at least one item.")
    for i, item in enumerate(cart_items):
        if not isinstance(item, dict):
            raise PaymentProcessingError(f"Cart item at index {i} must be a dictionary.")
        if "name" not in item:
            raise PaymentProcessingError(f"Cart item at index {i} must have a 'name' field.")
        if "price" not in item:
            raise PaymentProcessingError(f"Cart item at index {i} must have a 'price' field.")
        if "quantity" not in item:
            raise PaymentProcessingError(f"Cart item at index {i} must have a 'quantity' field.")
        if not isinstance(item["price"], (int, float)) or item["price"] < 0:
            raise PaymentProcessingError(f"Cart item '{item['name']}' has invalid price: {item['price']}.")
        if not isinstance(item["quantity"], int) or item["quantity"] <= 0:
            raise PaymentProcessingError(f"Cart item '{item['name']}' has invalid quantity: {item['quantity']}.")


def validate_payment_details(payment_details):
    if not isinstance(payment_details, dict):
        raise PaymentProcessingError("Payment details must be a dictionary.")
    required_fields = ["method", "token"]
    for field in required_fields:
        if field not in payment_details:
            raise PaymentProcessingError(f"Payment details must include '{field}'.")
    valid_methods = {"credit_card", "debit_card", "paypal", "bank_transfer"}
    if payment_details["method"] not in valid_methods:
        raise PaymentProcessingError(f"Invalid payment method: '{payment_details['method']}'.")


def calculate_cart_total_server_side(cart_items, product_catalog=None):
    """
    Calculate cart total using server-side prices from the product catalog
    rather than trusting client-supplied prices.
    """
    total = 0.0
    for item in cart_items:
        if product_catalog is not None:
            server_price = product_catalog.get_price(item.get("product_id") or item["name"])
            if server_price is None:
                raise PaymentProcessingError(
                    f"Product '{item['name']}' not found in catalog."
                )
            price = server_price
        else:
            price = item["price"]

        total += price * item["quantity"]

    return round(total, 2)


def calculate_discount(role):
    return DISCOUNT_MAP.get(role, 0.0)


def apply_discount(total, discount_percentage):
    if not 0.0 <= discount_percentage <= 1.0:
        raise PaymentProcessingError(
            f"Invalid discount percentage: {discount_percentage}. Must be between 0 and 1."
        )
    discount_amount = round(total * discount_percentage, 2)
    final_total = round(total - discount_amount, 2)
    if final_total < 0:
        final_total = 0.0
    return final_total, discount_amount


def process_payment_with_gateway(amount, payment_details, user_id):
    """
    Simulate sending payment to a payment gateway.
    In production, this would call an actual payment API.
    """
    if amount <= 0:
        raise PaymentProcessingError("Payment amount must be greater than zero.")

    return {
        "status": "success",
        "transaction_id": f"txn_{user_id}_{id(payment_details)}",
        "amount_charged": amount,
        "payment_method": payment_details["method"],
    }


def process_payment(user, cart_items, payment_details, user_repository=None, product_catalog=None):
    """
    Main payment processing function.

    Args:
        user: dict with at least 'id' and 'role' fields.
        cart_items: list of dicts, each with 'name', 'price', 'quantity' (and optionally 'product_id').
        payment_details: dict with 'method' and 'token' fields.
        user_repository: optional server-side user data source for role verification.
        product_catalog: optional server-side product catalog for price verification.

    Returns:
        dict with payment result details.
    """
    validate_user(user)
    validate_cart_items(cart_items)
    validate_payment_details(payment_details)

    verified_role = get_verified_user_role(user, user_repository)

    cart_total = calculate_cart_total_server_side(cart_items, product_catalog)

    discount_percentage = calculate_discount(verified_role)

    final_total, discount_amount = apply_discount(cart_total, discount_percentage)

    if final_total == 0.0 and cart_total > 0:
        gateway_result = {
            "status": "success",
            "transaction_id": f"txn_free_{user['id']}",
            "amount_charged": 0.0,
            "payment_method": "none",
        }
    elif final_total > 0:
        gateway_result = process_payment_with_gateway(final_total, payment_details, user["id"])
    else:
        raise PaymentProcessingError("Cannot process payment for an empty cart total.")

    return {
        "user_id": user["id"],
        "user_role": verified_role,
        "cart_total_before_discount": cart_total,
        "discount_percentage": f"{int(discount_percentage * 100)}%",
        "discount_amount": discount_amount,
        "final_total": final_total,
        "payment_result": gateway_result,
    }


